            const max = 3;
            const shown = list.slice(0, max).map(id => `<span class="waybill-tag">${id}</span>`).join("");
            if (list.length <= max) return shown;
            return `${shown}<span class="waybill-tag is-more">+${list.length - max}</span>`;
